-- 0002_baseline.sql
-- 完整建表 baseline（由 cmd/genmigration 从 ent schema 生成，勿手改）。
-- 改 ent/schema 后运行 `go run ./cmd/genmigration` 重新生成；CI 会 drift 检测。
-- 依赖 pre_0001_pgvector.sql 先安装 vector 扩展（Incident/Postmortem 的 embedding 列用）。
-- migrate.Run 优先用本文件建表；ent auto-migrate 作为兜底补充同步（处理边角差异）。

CREATE TABLE "teams" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "slug" character varying NOT NULL, "description" text NULL, "parent_team_id" character varying NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "teams_slug_key" ON "teams" ("slug");
CREATE INDEX "team_parent_team_id" ON "teams" ("parent_team_id");
CREATE TABLE "audit_logs" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "actor_user_id" bigint NOT NULL DEFAULT 0, "actor_name" character varying NOT NULL DEFAULT 'system', "action" character varying NOT NULL, "resource_type" character varying NOT NULL, "resource_id" bigint NOT NULL DEFAULT 0, "resource_name" character varying NULL, "result" character varying NOT NULL DEFAULT 'success', "detail" jsonb NULL, "ip" character varying NULL, "user_agent" character varying NULL, "created_at" timestamptz NOT NULL, PRIMARY KEY ("id"));
CREATE INDEX "auditlog_actor_user_id" ON "audit_logs" ("actor_user_id");
CREATE INDEX "auditlog_action" ON "audit_logs" ("action");
CREATE INDEX "auditlog_resource_type_resource_id" ON "audit_logs" ("resource_type", "resource_id");
CREATE INDEX "auditlog_created_at" ON "audit_logs" ("created_at");
CREATE TABLE "escalation_policies" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "repeat_times" bigint NOT NULL DEFAULT 0, "levels" jsonb NOT NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_escalation_policies" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "escalation_policies_teams_escalation_policies" FOREIGN KEY ("team_escalation_policies") REFERENCES "teams" ("id") ON DELETE SET NULL);
CREATE TABLE "users" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "username" character varying NOT NULL, "name" character varying NULL, "email" character varying NOT NULL, "phone" character varying NULL, "im_accounts" jsonb NULL, "status" character varying NOT NULL DEFAULT 'active', "timezone" character varying NOT NULL DEFAULT 'Asia/Shanghai', "password_hash" character varying NULL, "must_change_password" boolean NOT NULL DEFAULT false, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "users_username_key" ON "users" ("username");
CREATE UNIQUE INDEX "users_email_key" ON "users" ("email");
CREATE INDEX "user_status" ON "users" ("status");
CREATE TABLE "services" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "slug" character varying NOT NULL, "description" text NULL, "labels" jsonb NULL, "auto_create_incident" boolean NOT NULL DEFAULT true, "status" character varying NOT NULL DEFAULT 'active', "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "service_escalation_policy" bigint NULL, "team_services" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "services_escalation_policies_escalation_policy" FOREIGN KEY ("service_escalation_policy") REFERENCES "escalation_policies" ("id") ON DELETE SET NULL, CONSTRAINT "services_teams_services" FOREIGN KEY ("team_services") REFERENCES "teams" ("id") ON DELETE SET NULL);
CREATE UNIQUE INDEX "services_slug_key" ON "services" ("slug");
CREATE INDEX "service_status" ON "services" ("status");
CREATE TABLE "incidents" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "number" character varying NOT NULL, "title" character varying NOT NULL, "severity" character varying NOT NULL, "status" character varying NOT NULL DEFAULT 'triggered', "priority" character varying NOT NULL DEFAULT 'p3', "summary" character varying NULL, "escalated_count" bigint NOT NULL DEFAULT 0, "current_level" bigint NOT NULL DEFAULT 0, "merged_into" character varying NULL, "trigger_type" character varying NOT NULL DEFAULT 'auto', "trigger_source_event_id" character varying NULL, "war_room" jsonb NULL, "resolved_at" timestamptz NULL, "acked_at" timestamptz NULL, "closed_at" timestamptz NULL, "embedding" vector(1536) NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "escalation_policy_incidents" bigint NULL, "incident_assignee" bigint NULL, "service_incidents" bigint NULL, "team_incidents" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "incidents_escalation_policies_incidents" FOREIGN KEY ("escalation_policy_incidents") REFERENCES "escalation_policies" ("id") ON DELETE SET NULL, CONSTRAINT "incidents_users_assignee" FOREIGN KEY ("incident_assignee") REFERENCES "users" ("id") ON DELETE SET NULL, CONSTRAINT "incidents_services_incidents" FOREIGN KEY ("service_incidents") REFERENCES "services" ("id") ON DELETE SET NULL, CONSTRAINT "incidents_teams_incidents" FOREIGN KEY ("team_incidents") REFERENCES "teams" ("id") ON DELETE SET NULL);
CREATE UNIQUE INDEX "incidents_number_key" ON "incidents" ("number");
CREATE INDEX "incident_status_severity" ON "incidents" ("status", "severity");
CREATE INDEX "incident_team_incidents" ON "incidents" ("team_incidents");
CREATE INDEX "incident_service_incidents" ON "incidents" ("service_incidents");
CREATE INDEX "incident_resolved_at" ON "incidents" ("resolved_at");
CREATE TABLE "postmortems" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "status" character varying NOT NULL DEFAULT 'draft', "generated_by" character varying NOT NULL DEFAULT 'mixed', "sections" jsonb NOT NULL, "published_at" timestamptz NULL, "embedding" vector(1536) NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "incident_postmortem" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "postmortems_incidents_postmortem" FOREIGN KEY ("incident_postmortem") REFERENCES "incidents" ("id") ON DELETE SET NULL);
CREATE UNIQUE INDEX "postmortems_incident_postmortem_key" ON "postmortems" ("incident_postmortem");
CREATE TABLE "action_items" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "description" text NOT NULL, "owner_id" character varying NULL, "due_date" timestamptz NULL, "status" character varying NOT NULL DEFAULT 'open', "tracker_url" character varying NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "postmortem_action_items" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "action_items_postmortems_action_items" FOREIGN KEY ("postmortem_action_items") REFERENCES "postmortems" ("id") ON DELETE SET NULL);
CREATE INDEX "actionitem_status" ON "action_items" ("status");
CREATE INDEX "actionitem_due_date" ON "action_items" ("due_date");
CREATE TABLE "ai_insights" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "stage" character varying NOT NULL, "type" character varying NOT NULL, "content" jsonb NOT NULL, "confidence" real NOT NULL DEFAULT 0, "evidence" jsonb NULL, "status" character varying NOT NULL DEFAULT 'suggested', "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "incident_ai_insights" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "ai_insights_incidents_ai_insights" FOREIGN KEY ("incident_ai_insights") REFERENCES "incidents" ("id") ON DELETE SET NULL);
CREATE INDEX "aiinsight_incident_ai_insights" ON "ai_insights" ("incident_ai_insights");
CREATE INDEX "aiinsight_stage" ON "ai_insights" ("stage");
CREATE INDEX "aiinsight_status" ON "ai_insights" ("status");
CREATE TABLE "api_keys" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "token_hash" character varying NOT NULL, "prefix" character varying NOT NULL, "scope" jsonb NULL, "expires_at" timestamptz NULL, "last_used_at" timestamptz NULL, "status" character varying NOT NULL DEFAULT 'active', "created_at" timestamptz NOT NULL, "user_api_keys" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "api_keys_users_api_keys" FOREIGN KEY ("user_api_keys") REFERENCES "users" ("id") ON DELETE NO ACTION);
CREATE UNIQUE INDEX "apikey_token_hash" ON "api_keys" ("token_hash");
CREATE INDEX "apikey_status" ON "api_keys" ("status");
CREATE TABLE "schedules" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "type" character varying NOT NULL, "timezone" character varying NOT NULL DEFAULT 'Asia/Shanghai', "layers" jsonb NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_schedules" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "schedules_teams_schedules" FOREIGN KEY ("team_schedules") REFERENCES "teams" ("id") ON DELETE SET NULL);
CREATE TABLE "escalation_policy_schedules" ("escalation_policy_id" bigint NOT NULL, "schedule_id" bigint NOT NULL, PRIMARY KEY ("escalation_policy_id", "schedule_id"), CONSTRAINT "escalation_policy_schedules_escalation_policy_id" FOREIGN KEY ("escalation_policy_id") REFERENCES "escalation_policies" ("id") ON DELETE CASCADE, CONSTRAINT "escalation_policy_schedules_schedule_id" FOREIGN KEY ("schedule_id") REFERENCES "schedules" ("id") ON DELETE CASCADE);
CREATE TABLE "integrations" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "type" character varying NOT NULL, "config" jsonb NULL, "token" character varying NOT NULL, "enabled" boolean NOT NULL DEFAULT true, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "service_integrations" bigint NULL, "team_integrations" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "integrations_services_integrations" FOREIGN KEY ("service_integrations") REFERENCES "services" ("id") ON DELETE SET NULL, CONSTRAINT "integrations_teams_integrations" FOREIGN KEY ("team_integrations") REFERENCES "teams" ("id") ON DELETE SET NULL);
CREATE TABLE "events" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "source_event_id" character varying NOT NULL, "source" character varying NOT NULL, "severity" character varying NOT NULL, "status" character varying NOT NULL, "summary" character varying NOT NULL, "detail" jsonb NULL, "labels" jsonb NULL, "dedup_key" character varying NOT NULL, "received_at" timestamptz NOT NULL, "is_noise" boolean NOT NULL DEFAULT false, "created_at" timestamptz NOT NULL, "event_incident" bigint NULL, "integration_events" bigint NULL, "service_events" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "events_incidents_incident" FOREIGN KEY ("event_incident") REFERENCES "incidents" ("id") ON DELETE SET NULL, CONSTRAINT "events_integrations_events" FOREIGN KEY ("integration_events") REFERENCES "integrations" ("id") ON DELETE SET NULL, CONSTRAINT "events_services_events" FOREIGN KEY ("service_events") REFERENCES "services" ("id") ON DELETE SET NULL);
CREATE INDEX "event_dedup_key" ON "events" ("dedup_key");
CREATE UNIQUE INDEX "event_source_source_event_id_status" ON "events" ("source", "source_event_id", "status");
CREATE INDEX "event_severity_received_at" ON "events" ("severity", "received_at");
CREATE INDEX "event_is_noise" ON "events" ("is_noise");
CREATE TABLE "im_account_bindings" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "platform" character varying NOT NULL, "account_id" character varying NOT NULL, "created_at" timestamptz NOT NULL, "user_im_bindings" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "im_account_bindings_users_im_bindings" FOREIGN KEY ("user_im_bindings") REFERENCES "users" ("id") ON DELETE NO ACTION);
CREATE UNIQUE INDEX "imaccountbinding_platform_account_id" ON "im_account_bindings" ("platform", "account_id");
CREATE TABLE "incident_actions" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "type" character varying NOT NULL, "actor" jsonb NOT NULL, "payload" jsonb NULL, "via" character varying NOT NULL, "result" character varying NOT NULL DEFAULT 'success', "timestamp" timestamptz NOT NULL, "incident_actions" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "incident_actions_incidents_actions" FOREIGN KEY ("incident_actions") REFERENCES "incidents" ("id") ON DELETE SET NULL);
CREATE INDEX "incidentaction_incident_actions" ON "incident_actions" ("incident_actions");
CREATE INDEX "incidentaction_timestamp" ON "incident_actions" ("timestamp");
CREATE INDEX "incidentaction_via_timestamp" ON "incident_actions" ("via", "timestamp");
CREATE TABLE "incident_responders" ("incident_id" bigint NOT NULL, "user_id" bigint NOT NULL, PRIMARY KEY ("incident_id", "user_id"), CONSTRAINT "incident_responders_incident_id" FOREIGN KEY ("incident_id") REFERENCES "incidents" ("id") ON DELETE CASCADE, CONSTRAINT "incident_responders_user_id" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON DELETE CASCADE);
CREATE TABLE "notification_rules" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "condition" jsonb NOT NULL, "channels" jsonb NOT NULL, "template_id" character varying NULL, "quiet_hours" jsonb NULL, "enabled" boolean NOT NULL DEFAULT true, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_notification_rules" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "notification_rules_teams_notification_rules" FOREIGN KEY ("team_notification_rules") REFERENCES "teams" ("id") ON DELETE SET NULL);
CREATE TABLE "notification_templates" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "channel" character varying NOT NULL, "format" character varying NOT NULL, "title_template" character varying NOT NULL, "body_template" text NOT NULL, "actions" jsonb NULL, "builtin" boolean NOT NULL DEFAULT false, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_notification_templates" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "notification_templates_teams_notification_templates" FOREIGN KEY ("team_notification_templates") REFERENCES "teams" ("id") ON DELETE SET NULL);
CREATE TABLE "raw_events" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "payload" bytea NOT NULL, "headers" jsonb NULL, "received_at" timestamptz NOT NULL, "status" character varying NOT NULL DEFAULT 'received', "error" text NULL, "created_at" timestamptz NOT NULL, "integration_raw_events" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "raw_events_integrations_raw_events" FOREIGN KEY ("integration_raw_events") REFERENCES "integrations" ("id") ON DELETE SET NULL);
CREATE INDEX "rawevent_status_received_at" ON "raw_events" ("status", "received_at");
CREATE TABLE "roles" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "description" text NULL, "builtin" boolean NOT NULL DEFAULT false, "scope_level" character varying NOT NULL, "permissions" jsonb NOT NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "roles_name_key" ON "roles" ("name");
CREATE TABLE "role_bindings" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "scope_level" character varying NOT NULL, "team_id" character varying NULL, "granted_by" character varying NULL, "expires_at" timestamptz NULL, "granted_at" timestamptz NOT NULL, "role_role_bindings" bigint NOT NULL, "user_role_bindings" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "role_bindings_roles_role_bindings" FOREIGN KEY ("role_role_bindings") REFERENCES "roles" ("id") ON DELETE NO ACTION, CONSTRAINT "role_bindings_users_role_bindings" FOREIGN KEY ("user_role_bindings") REFERENCES "users" ("id") ON DELETE NO ACTION);
CREATE TABLE "rotations" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "shift_length" character varying NOT NULL DEFAULT '24h', "handoff_time" character varying NOT NULL DEFAULT '09:00', "rotation_type" character varying NOT NULL, "start_date" timestamptz NOT NULL, "end_date" timestamptz NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "schedule_rotations" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "rotations_schedules_rotations" FOREIGN KEY ("schedule_rotations") REFERENCES "schedules" ("id") ON DELETE SET NULL);
CREATE TABLE "rotation_participants" ("rotation_id" bigint NOT NULL, "user_id" bigint NOT NULL, PRIMARY KEY ("rotation_id", "user_id"), CONSTRAINT "rotation_participants_rotation_id" FOREIGN KEY ("rotation_id") REFERENCES "rotations" ("id") ON DELETE CASCADE, CONSTRAINT "rotation_participants_user_id" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON DELETE CASCADE);
CREATE TABLE "runbooks" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "type" character varying NOT NULL, "trigger" jsonb NULL, "content_markdown" text NULL, "steps" jsonb NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_runbooks" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "runbooks_teams_runbooks" FOREIGN KEY ("team_runbooks") REFERENCES "teams" ("id") ON DELETE SET NULL);
CREATE TABLE "service_runbooks" ("service_id" bigint NOT NULL, "runbook_id" bigint NOT NULL, PRIMARY KEY ("service_id", "runbook_id"), CONSTRAINT "service_runbooks_service_id" FOREIGN KEY ("service_id") REFERENCES "services" ("id") ON DELETE CASCADE, CONSTRAINT "service_runbooks_runbook_id" FOREIGN KEY ("runbook_id") REFERENCES "runbooks" ("id") ON DELETE CASCADE);
CREATE TABLE "service_schedules" ("service_id" bigint NOT NULL, "schedule_id" bigint NOT NULL, PRIMARY KEY ("service_id", "schedule_id"), CONSTRAINT "service_schedules_service_id" FOREIGN KEY ("service_id") REFERENCES "services" ("id") ON DELETE CASCADE, CONSTRAINT "service_schedules_schedule_id" FOREIGN KEY ("schedule_id") REFERENCES "schedules" ("id") ON DELETE CASCADE);
CREATE TABLE "suppression_rules" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "match_labels" jsonb NOT NULL, "time_window" jsonb NULL, "severity_filter" jsonb NULL, "action" character varying NOT NULL DEFAULT 'suppress', "reduce_to" character varying NULL, "preserve_critical" boolean NOT NULL DEFAULT true, "enabled" boolean NOT NULL DEFAULT true, "expires_at" timestamptz NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_suppression_rules" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "suppression_rules_teams_suppression_rules" FOREIGN KEY ("team_suppression_rules") REFERENCES "teams" ("id") ON DELETE SET NULL);
CREATE TABLE "team_role_bindings" ("team_id" bigint NOT NULL, "role_binding_id" bigint NOT NULL, PRIMARY KEY ("team_id", "role_binding_id"), CONSTRAINT "team_role_bindings_team_id" FOREIGN KEY ("team_id") REFERENCES "teams" ("id") ON DELETE CASCADE, CONSTRAINT "team_role_bindings_role_binding_id" FOREIGN KEY ("role_binding_id") REFERENCES "role_bindings" ("id") ON DELETE CASCADE);
CREATE TABLE "team_users" ("team_id" bigint NOT NULL, "user_id" bigint NOT NULL, PRIMARY KEY ("team_id", "user_id"), CONSTRAINT "team_users_team_id" FOREIGN KEY ("team_id") REFERENCES "teams" ("id") ON DELETE CASCADE, CONSTRAINT "team_users_user_id" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON DELETE CASCADE);
CREATE TABLE "timeline_items" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "timestamp" timestamptz NOT NULL, "type" character varying NOT NULL, "actor" jsonb NOT NULL, "content" text NOT NULL, "detail" jsonb NULL, "source" character varying NOT NULL, "created_at" timestamptz NOT NULL, "incident_timeline" bigint NULL, PRIMARY KEY ("id"), CONSTRAINT "timeline_items_incidents_timeline" FOREIGN KEY ("incident_timeline") REFERENCES "incidents" ("id") ON DELETE SET NULL);
CREATE INDEX "timelineitem_incident_timeline" ON "timeline_items" ("incident_timeline");
CREATE INDEX "timelineitem_timestamp" ON "timeline_items" ("timestamp");
CREATE INDEX "timelineitem_type" ON "timeline_items" ("type");
